package com.oyuki.complaint.entity;
import com.oyuki.complaint.enums.ComplaintStatus; import com.oyuki.user.entity.User; import jakarta.persistence.*; import lombok.*; import java.time.LocalDateTime;
@Entity @Table(name="complaints") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder
public class Complaint { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="customer_id") private User customer; @Column(nullable=false,length=160) private String subject; @Column(nullable=false,length=3000) private String message; @Column(name="order_id") private Long orderId; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) @Builder.Default private ComplaintStatus status=ComplaintStatus.OPEN; @Column(length=2000) private String resolution; private LocalDateTime createdAt; private LocalDateTime updatedAt; @PrePersist void create(){createdAt=updatedAt=LocalDateTime.now();} @PreUpdate void update(){updatedAt=LocalDateTime.now();} }